for f in files:
    with open(f, 'r', encoding='utf-8') as fh:
        content = fh.read()
    content = old_wa_re.sub(svg['whatsapp'], content)
    for pattern, repl in replacements:
        content = pattern.sub(repl, content)
    content = content.replace(logo_old_nav, logo_new_nav)
    content = content.replace(logo_old_foot, logo_new_foot)
    with open(f, 'w', encoding='utf-8') as fh:
        fh.write(content)
    print('Done:', f)

